from dupan import DuPanFileSystem
import os
import requests

def get_baidu_file_list(access_token, bduss, file_path):
    # 1. 登录（用BDUSS）
    cookie = "BDUSS=" + bduss + "; STOKEN=" +access_token
    fs = DuPanFileSystem.login(cookie)

    # 2. 获取文件直链 dlink
    dlink = fs.get_url(file_path)
    print(dlink)
    return dlink
    # 3. Aria2 RPC 下载（不限速）
